const elApiKey = $('settings').first().json.ELEVENLABS_API_KEY;
const agentId = $('settings').first().json.EVE_AGENT_ID;
const phoneNumberId = $('settings').first().json.PHONE_NUMBER_ID;
const elHeaders = { 'xi-api-key': elApiKey, 'Content-Type': 'application/json' };

const trigger = $('workflow_trigger').first().json;
const contentText = trigger.content_text || '';
const contentTitle = trigger.content_title || 'Untitled';
const contentType = trigger.content_type || 'content';
const callbackMode = trigger.callback_mode || 'review';
const self = this;

if (contentText === '') {
  return [{ json: { result: 'Error: No content_text provided for knowledge base injection.' } }];
}

try {
  // Step 0: Get the caller's phone number from most recent COMPLETED inbound call
  const convosResp = await self.helpers.httpRequest({
    method: 'GET',
    url: 'https://api.elevenlabs.io/v1/convai/conversations?agent_id=' + agentId + '&page_size=10',
    headers: elHeaders
  });

  var callbackPhone = '';
  var eveAgentNumber = '';
  const convos = convosResp.conversations || [];
  for (var i = 0; i < convos.length; i++) {
    // Only check completed calls
    if (convos[i].status !== 'done') continue;

    var convoDetail = await self.helpers.httpRequest({
      method: 'GET',
      url: 'https://api.elevenlabs.io/v1/convai/conversations/' + convos[i].conversation_id,
      headers: elHeaders
    });
    var phoneCall = (convoDetail.metadata || {}).phone_call || {};
    if (phoneCall.direction === 'inbound' && phoneCall.external_number) {
      callbackPhone = phoneCall.external_number;
      eveAgentNumber = phoneCall.agent_number || '';
      break;
    }
  }

  if (callbackPhone === '') {
    return [{ json: { result: 'Error: Could not find caller phone number from recent conversations.' } }];
  }

  // SAFETY: Never call Eve's own number (would create infinite loop)
  if (eveAgentNumber && callbackPhone === eveAgentNumber) {
    return [{ json: { result: 'Error: Callback phone matches Eve agent number. Aborting to prevent loop.' } }];
  }

  // Step 1: Get current agent config
  const agentResp = await self.helpers.httpRequest({
    method: 'GET',
    url: 'https://api.elevenlabs.io/v1/convai/agents/' + agentId,
    headers: elHeaders
  });

  var cc = agentResp.conversation_config || {};
  var ag = cc.agent || {};
  var pr = ag.prompt || {};
  var existingKB = pr.knowledge_base || [];

  var sessionDocs = existingKB.filter(function(doc) {
    return doc.name && doc.name.indexOf('Eve Session:') === 0;
  });
  var remainingKB = existingKB.filter(function(doc) {
    return !(doc.name && doc.name.indexOf('Eve Session:') === 0);
  });

  // Step 2: Detach old session docs then delete
  if (sessionDocs.length > 0) {
    await self.helpers.httpRequest({
      method: 'PATCH',
      url: 'https://api.elevenlabs.io/v1/convai/agents/' + agentId,
      headers: elHeaders,
      body: JSON.stringify({ conversation_config: { agent: { prompt: { knowledge_base: remainingKB } } } })
    });
    for (var d = 0; d < sessionDocs.length; d++) {
      try {
        await self.helpers.httpRequest({
          method: 'DELETE',
          url: 'https://api.elevenlabs.io/v1/convai/knowledge-base/' + sessionDocs[d].id,
          headers: { 'xi-api-key': elApiKey }
        });
      } catch (delErr) {}
    }
  }

  // Step 3: Create new KB document
  var timestamp = new Date().toISOString().replace(/[:.]/g, '-');
  var docName = 'Eve Session: ' + contentType + ' - ' + contentTitle + ' - ' + timestamp;
  var fileName = contentTitle.replace(/[^a-zA-Z0-9]/g, '_').substring(0, 50) + '.txt';

  var boundary = '----n8nFormBoundary' + Date.now();
  var formBody = '--' + boundary + '\r\n';
  formBody += 'Content-Disposition: form-data; name="name"\r\n\r\n';
  formBody += docName + '\r\n';
  formBody += '--' + boundary + '\r\n';
  formBody += 'Content-Disposition: form-data; name="file"; filename="' + fileName + '"\r\n';
  formBody += 'Content-Type: text/plain\r\n\r\n';
  formBody += contentText + '\r\n';
  formBody += '--' + boundary + '--\r\n';

  var kbResp = await self.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.elevenlabs.io/v1/convai/knowledge-base',
    headers: {
      'xi-api-key': elApiKey,
      'Content-Type': 'multipart/form-data; boundary=' + boundary
    },
    body: formBody
  });

  var newDocId = kbResp.id || kbResp.document_id || '';
  if (newDocId === '') {
    return [{ json: { result: 'Error: Failed to create KB doc. Response: ' + JSON.stringify(kbResp) } }];
  }

  // Step 4: Attach new KB doc to agent
  var updatedKB = remainingKB.slice();
  updatedKB.push({ type: 'file', id: newDocId, name: docName });

  await self.helpers.httpRequest({
    method: 'PATCH',
    url: 'https://api.elevenlabs.io/v1/convai/agents/' + agentId,
    headers: elHeaders,
    body: JSON.stringify({ conversation_config: { agent: { prompt: { knowledge_base: updatedKB } } } })
  });

  // Step 5: Update first_message
  var firstMessage = '';
  if (callbackMode === 'brainstorm') {
    firstMessage = 'Hey darling, I have got that ' + contentType.replace(/_/g, ' ') + ' loaded up, ' + contentTitle + '. Want me to summarize the key points first, or should we dive straight into brainstorming?';
  } else {
    firstMessage = 'Hey darling, I have got your ' + contentType.replace(/_/g, ' ') + ' loaded up, ' + contentTitle + '. Want the highlights first, or should we dive straight into revisions?';
  }

  await self.helpers.httpRequest({
    method: 'PATCH',
    url: 'https://api.elevenlabs.io/v1/convai/agents/' + agentId,
    headers: elHeaders,
    body: JSON.stringify({ conversation_config: { agent: { first_message: firstMessage } } })
  });

  // Step 6: Make outbound call to the caller's phone
  var callResp = await self.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.elevenlabs.io/v1/convai/twilio/outbound-call',
    headers: elHeaders,
    body: JSON.stringify({
      agent_id: agentId,
      agent_phone_number_id: phoneNumberId,
      to_number: callbackPhone
    })
  });

  var callId = callResp.call_id || callResp.id || 'initiated';
  return [{ json: { result: 'KB updated with "' + contentTitle + '" (' + contentText.length + ' chars). Calling ' + callbackPhone + ' in ' + callbackMode + ' mode. Call ID: ' + callId, call_id: callId, kb_doc_id: newDocId, callback_phone: callbackPhone } }];

} catch (err) {
  return [{ json: { result: 'Error in Eve callback flow: ' + err.message } }];
}
